-- Seed: laboratories (CodeSystem BRFabricantePNI v1.1.2) + vaccines (Calendário PNI)
-- Unsafe: do not re-run (no ON CONFLICT guard — IDs are generated by the DB)

-- ---------------------------------------------------------------------------
-- Laboratórios — todos os fabricantes do CodeSystem BRFabricantePNI
-- ---------------------------------------------------------------------------
WITH inserted_labs AS (
  RETURNING id, name
),

-- ---------------------------------------------------------------------------
-- Vacinas — calendário PNI vigente (vinculadas ao fabricante principal no SUS)
-- ---------------------------------------------------------------------------
vaccines_data (vaccine_name, lab_name) AS (
  VALUES
    -- Imunobiológicos do calendário de rotina
    ('BCG',                               'FUNDACAO OSWALDO CRUZ'),
    ('Hepatite B',                        'INSTITUTO BUTANTAN'),
    ('Pentavalente (DTP+Hib+HB)',         'FUNDACAO OSWALDO CRUZ'),
    ('VIP — Poliomielite Inativada',      'SANOFI PASTEUR'),
    ('VOP — Poliomielite Oral Bivalente', 'FUNDACAO OSWALDO CRUZ'),
    ('Rotavírus Humano (VORH)',           'GLAXOSMITHKLINE BRASIL LTDA.'),
    ('Pneumocócica 10-valente',          'FUNDACAO OSWALDO CRUZ'),
    ('Pneumocócica 13-valente',          'LABORATORIOS PFIZER LTDA'),
    ('Meningocócica C Conjugada',        'LABORATORIOS PFIZER LTDA'),
    ('Meningocócica ACWY',               'SANOFI PASTEUR'),
    ('Febre Amarela',                    'FUNDACAO OSWALDO CRUZ'),
    ('Tríplice Viral (SCR)',             'FUNDACAO OSWALDO CRUZ'),
    ('Tetra Viral (SCRV)',               'MERCK SHARP DOHME CO., INC.'),
    ('Varicela',                         'MERCK SHARP DOHME CO., INC.'),
    ('DTP — Tríplice Bacteriana',        'INSTITUTO BUTANTAN'),
    ('dT — Dupla Adulto',               'INSTITUTO BUTANTAN'),
    ('dTpa — Tríplice Acelular Adulto', 'SANOFI MEDLEY FARMACEUTICA LTDA'),
    ('Hepatite A',                       'INSTITUTO BUTANTAN'),
    ('HPV Quadrivalente',               'MERCK SHARP DOHME CO., INC.'),
    ('Dengue (Qdenga)',                  'TAKEDA PHARMA LTDA.'),
    ('Influenza',                        'INSTITUTO BUTANTAN'),
    -- COVID-19
    ('COVID-19 CoronaVac',              'INSTITUTO BUTANTAN'),
    ('COVID-19 BNT162b2 (Comirnaty)',   'PFIZER MANUFACTURING BELGIUM NV - BELGICA'),
    ('COVID-19 ChAdOx1 (Covishield)',   'FUNDACAO OSWALDO CRUZ'),
    ('COVID-19 Ad26.COV2.S (Janssen)', 'JANSSEN PHARMACEUTICA NV'),
    ('COVID-19 mRNA-1273 (Spikevax)',  'MODERNA BIOTECH')
)
SELECT vd.vaccine_name, il.id
FROM vaccines_data vd
JOIN inserted_labs il ON il.name = vd.lab_name;
